INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, "", "", 13010020, "", 111031, "", 301, 10, "独自の改修を施すぞ\n機体の縮小化そして\n各種機能を改良だ", "");
