INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, "", "", 13010027, "", 111031, "", 301, 10, "いや、そもそもなぜ\nたい焼き麦しゅわが\n組み込まれていたか", "");
