INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, "", "", 13020023, "", 111031, "", 302, 10, "ふむ…これは僥倖\nかくなる上は再び\n潜航してみるか…", "");
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, "", "", 13020024, "", 0, "", 302, "", "", "");
