INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, "", "", 13020026, "", 111031, "", 302, 10, "存外意義あるものだ\n資材ダイビングとか\nいう新種の探索行は", "");
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, "", "", 13020027, "", 0, "", 302, "", 1, "");
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, "", "", 13020028, "", 111031, "", 302, 10, "まあ万一溺れたとて\n後輩たちの誰ぞが\nきっと気付くだろう", "");
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, "", "", 13020029, "", 0, "", 302, "", 1, "");
