INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, "", "", 13030008, "", 111031, "", 303, 10, "ふふふ…我ながら\n納得の出来栄え…", "");
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (91, "", "", 13030009, "", 0, "", 303, "", "", "");
INSERT INTO `v1_85255ec2b65043132c2091154ff2d83ff28ac33ab7f384dfac370e86dfe8fa1f` VALUES (11, "", "", 13030010, "", 111031, "", 303, 10, "外観の完成度も\nさることながら\n特筆すべきは機能だ", "");
